//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Inserted/deleted run + paragraph content revisions and accept/reject
//! semantics".
//!
//! Each `#[test]` encodes a behavioural constraint mined from ECMA-376 /
//! ISO 29500-1 / MS-OI29500 for tracked-change *content* revisions (w:ins,
//! w:del, w:delText, w:delInstrText, w:moveFrom, deleted paragraph marks).
//!
//! A FAILING assertion here is NOT a flaky test: it encodes a real
//! Word-compliance gap in the stemma engine. Do NOT weaken the assertion to
//! make it pass — fix the engine (or, if the test itself encodes a wrong
//! expectation, fix the test from the spec rule, never from current behaviour).
//!
//! METHODOLOGY (consumption vs. save): stemma round-trips UNTOUCHED content
//! byte-verbatim. So `reserialize()` of an unedited document reflects stemma's
//! verbatim-preservation contract, not Word's render normalization. The xml*
//! expectations below are restricted to markup the serializer actively
//! preserves/restructures (element identity + nesting + xml:space), and the
//! accept/reject expectations test Word *consumption* semantics on the read
//! side. Opens-clean is a validity property of the bytes.

use stemma::ExportOptions;
use stemma::api::{Document, validate};

// ─── Prelude: minimal-docx plumbing (mirrors the shared spec-suite prelude) ──

/// Build a valid minimal `.docx`. `body_xml` is the inner content of
/// `<w:body>…</w:body>` (callers include their own `<w:sectPr/>`).
///
/// `extra_parts` is a list of `(part_path, xml_bytes)` written verbatim into the
/// zip; for each one whose path looks like a known WordprocessingML part we add
/// the matching `[Content_Types].xml` override so Word resolves it.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type overrides for any extra parts we recognise.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (path, _) in extra_parts {
        let ct = if path.ends_with("styles.xml") {
            Some("application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml")
        } else if path.ends_with("numbering.xml") {
            Some("application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml")
        } else {
            None
        };
        if let Some(ct) = ct {
            overrides.push_str(&format!(
                r#"<Override PartName="/{path}" ContentType="{ct}"/>"#
            ));
        }
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (path, xml) in extra_parts {
            zip.start_file(*path, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let archive = stemma::docx::DocxArchive::read(docx).expect("read docx");
    String::from_utf8_lossy(
        archive
            .get("word/document.xml")
            .expect("document.xml present"),
    )
    .into_owned()
}

/// Parse → serialize → return the re-emitted `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&ExportOptions::default())
        .expect("serialize for reserialize");
    document_xml_of(&out)
}

/// Accept-all visible body text.
fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
}

/// Reject-all visible body text.
fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
}

/// `(ok, joined-issue-detail)` for `validate(bytes)`.
fn opens_clean(bytes: &[u8]) -> (bool, String) {
    let report = validate(bytes);
    let detail = report
        .issues
        .iter()
        .map(|i| format!("[{:?}] {}", i.code, i.message))
        .collect::<Vec<_>>()
        .join("; ");
    (report.ok, detail)
}

/// xmlRegex substitute for `<w:del [^>]*>(?:(?!</w:del>).)*?<w:t[ >]`: true iff a
/// `<w:t…>` start tag appears inside a `<w:del>…</w:del>` region (the del
/// regions here are non-nested). Presence == a Word-incompliance (deleted text
/// must be w:delText, never w:t).
fn w_t_appears_inside_w_del(xml: &str) -> bool {
    let mut search_from = 0usize;
    while let Some(rel) = xml[search_from..].find("<w:del ") {
        let open = search_from + rel;
        let Some(end_rel) = xml[open..].find("</w:del>") else {
            break;
        };
        let region = &xml[open..open + end_rel];
        let mut i = 0usize;
        while let Some(trel) = region[i..].find("<w:t") {
            let tag = i + trel;
            let after = region.as_bytes().get(tag + 4).copied();
            if matches!(after, Some(b'>') | Some(b' ') | Some(b'/')) {
                return true;
            }
            i = tag + 4;
        }
        search_from = open + end_rel + "</w:del>".len();
    }
    false
}

/// xmlRegex substitute for `<w:delText[^>]*xml:space="preserve"`: a w:delText
/// start tag carrying xml:space="preserve" before its closing `>`.
fn deltext_has_space_preserve(xml: &str) -> bool {
    let mut from = 0usize;
    while let Some(rel) = xml[from..].find("<w:delText") {
        let tag = from + rel;
        let Some(gt_rel) = xml[tag..].find('>') else {
            break;
        };
        let open_tag = &xml[tag..tag + gt_rel];
        if open_tag.contains(r#"xml:space="preserve""#) {
            return true;
        }
        from = tag + gt_rel + 1;
    }
    false
}

/// xmlRegex substitute for `<w:del\b[^>]*>\s*<w:r>\s*<w:delInstrText`: a
/// delInstrText run nested directly inside a w:del container (whitespace-tolerant).
fn del_wraps_delinstrtext_run(xml: &str) -> bool {
    let mut from = 0usize;
    while let Some(rel) = xml[from..].find("<w:del") {
        let tag = from + rel;
        // require <w:del> or <w:del …>, not <w:delText / <w:delInstrText
        let after = xml.as_bytes().get(tag + 6).copied();
        if !matches!(after, Some(b'>') | Some(b' ')) {
            from = tag + 6;
            continue;
        }
        let Some(gt_rel) = xml[tag..].find('>') else {
            break;
        };
        let rest = xml[tag + gt_rel + 1..].trim_start();
        if let Some(after_r) = rest.strip_prefix("<w:r>")
            && after_r.trim_start().starts_with("<w:delInstrText")
        {
            return true;
        }
        from = tag + gt_rel + 1;
    }
    false
}

