#[test]
fn ins_encapsulates_multiple_runs_accept_keeps_all_reject_drops_all() {
    let body = r#"<w:p><w:r><w:t>pre </w:t></w:r><w:ins w:id="8" w:author="A" w:date="2006-03-31T12:50:00Z"><w:r><w:t>foo</w:t></w:r><w:r><w:t>bar</w:t></w:r></w:ins><w:r><w:t xml:space="preserve"> post</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b).trim(),
        "pre foobar post",
        "ECMA-376 §17.13.1 / §17.13.5.18 — a single w:ins encapsulates both runs as one insertion; accepting keeps the concatenation of all inner runs joined to surrounding text"
    );
    assert_eq!(
        reject_text(&b).trim(),
        "pre  post",
        "ECMA-376 §17.13.1 / §17.13.5.18 — rejecting the one insertion drops ALL inner runs ('foo' and 'bar'), leaving only the untracked surrounding text"
    );
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "ECMA-376 §17.13.5.18 — a w:ins wrapping multiple runs is the standard inline-insertion encoding; Word opens it without repair. issues: {detail}"
    );
}

#[test]
fn deleted_field_code_serializes_delinstrtext_not_t() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:del w:id="7" w:author="Joe" w:date="2006-03-31T12:50:00Z"><w:r><w:delInstrText xml:space="preserve"> PAGE </w:delInstrText></w:r></w:del><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>1</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        xml.contains("delInstrText"),
        "ECMA-376 §17.16.13 — a field-code run inside w:del must serialize as w:delInstrText, never collapsed to w:t/w:instrText; the deleted-field shape must survive the roundtrip"
    );
    assert_eq!(
        reject_text(&b).trim(),
        "1",
        "ECMA-376 §17.16.13 / §17.13.5.14 / §17.3.3.7 — rejecting the deletion restores the field code as w:instrText (a field code, not visible body text); the only visible text is the field result '1' — the restored ' PAGE ' instruction must NOT appear as body text"
    );
    assert_eq!(
        accept_text(&b).trim(),
        "1",
        "ECMA-376 §17.16.13 — accepting the deletion drops the deleted field code entirely; the field result run '1' remains, so visible text is '1'"
    );
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "ECMA-376 §17.16.13 — delInstrText nested inside w:del inside a complex field is conformant; Word opens it without repair. issues: {detail}"
    );
}

