#[test]
fn del_then_ins_replacement_no_t_inside_del() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">The quick brown fox jumps over the </w:t></w:r><w:del w:id="1" w:author="Ed" w:date="2006-03-31T12:50:00Z"><w:r><w:delText>lazy</w:delText></w:r></w:del><w:ins w:id="2" w:author="Ed" w:date="2006-03-31T12:50:00Z"><w:r><w:t>jet lagged</w:t></w:r></w:ins><w:r><w:t xml:space="preserve"> dog.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        xml.contains("<w:delText"),
        "ECMA-376 §17.3.3.7 — deleted text inside w:del must serialize as w:delText; the deleted 'lazy' run must keep its delText element"
    );
    assert!(
        !w_t_appears_inside_w_del(&xml),
        "ECMA-376 §17.3.3.7 / §17.13.1 — a w:t element must NEVER appear inside a w:del region (deleted text is always w:delText); a w:t before the del closes is a Word-incompliance. (xmlRegex `<w:del [^>]*>(?:(?!</w:del>).)*?<w:t[ >]` must NOT match)"
    );
}

